# IoT Firmware Analyzer
import os
import hashlib
import subprocess
import re
from pathlib import Path

class IoTFirmwareAnalyzer:
    def __init__(self, firmware_path):
        self.firmware_path = firmware_path
        self.findings = []

    def calculate_hashes(self):
        """Calculate file hashes for integrity verification."""
        hashes = {}
        for ext in ['sha256', 'md5']:
            try:
                result = subprocess.run(
                    [f'{ext}sum', self.firmware_path],
                    capture_output=True, text=True
                )
                hashes[ext] = result.stdout.split()[0]
            except Exception:
                pass
        return hashes

    def extract_firmware(self):
        """Extract firmware using binwalk."""
        output_dir = f"{self.firmware_path}_extracted"
        try:
            subprocess.run(['binwalk', '-e', '-C', output_dir, self.firmware_path],
                         capture_output=True)
            return output_dir
        except FileNotFoundError:
            return None

    def find_hardcoded_credentials(self, extracted_dir):
        """Search for hardcoded credentials in firmware."""
        patterns = {
            'password': r'password\s*[=:]\s*(\S+)',
            'admin': r'admin\s*[=:]\s*(\S+)',
            'root': r'root:\S+:',
            'api_key': r'api[_-]?key\s*[=:]\s*[\"\']([^\"\']+)',
        }

        found = []
        for root, dirs, files in os.walk(extracted_dir):
            for fname in files:
                fpath = os.path.join(root, fname)
                try:
                    with open(fpath, 'r', errors='ignore') as f:
                        content = f.read()
                        for name, pattern in patterns.items():
                            matches = re.findall(pattern, content, re.IGNORECASE)
                            if matches:
                                found.append({'file': fpath, 'type': name, 'matches': matches[:5]})
                except (IOError, PermissionError):
                    pass
        return found

    def check_debug_interfaces(self, extracted_dir):
        """Check for exposed debug interfaces."""
        debug_files = []
        for root, dirs, files in os.walk(extracted_dir):
            for fname in files:
                if any(d in fname.lower() for d in ['jtag', 'uart', 'serial', 'debug', 'console']):
                    debug_files.append(os.path.join(root, fname))
        return debug_files

    def analyze(self):
        """Run full firmware analysis."""
        print(f"Analyzing: {self.firmware_path}")
        hashes = self.calculate_hashes()
        print(f"SHA256: {hashes.get('sha256', 'N/A')}")

        extracted = self.extract_firmware()
        if extracted:
            creds = self.find_hardcoded_credentials(extracted)
            debug = self.check_debug_interfaces(extracted)
            print(f"Hardcoded credentials: {len(creds)}")
            print(f"Debug interfaces: {len(debug)}")
